import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { toast } from 'react-toastify';

const Members = () => {
    const [members, setMembers] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchMembers();
    }, []);

    const fetchMembers = async () => {
        try {
            const res = await api.get('/admin/users');
            setMembers(res.data.filter(u => u.role === 'member'));
        } catch (err) {
            console.error(err);
            toast.error('Failed to fetch members');
        } finally {
            setLoading(false);
        }
    };

    const toggleStatus = async (id, currentStatus) => {
        const newStatus = currentStatus === 'active' ? 'suspended' : 'active';
        try {
            await api.patch(`/admin/users/${id}/status`, { status: newStatus });
            setMembers(m => m.map(u => u._id === id ? { ...u, status: newStatus } : u));
            toast.success(`Member ${newStatus === 'active' ? 'activated' : 'suspended'}`);
        } catch (err) {
            toast.error('Failed to update status');
        }
    };

    return (
        <div className="fade-in p-6">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Member Management</h2>
                <div className="text-sm text-gray-500">Total Members: {members.length}</div>
            </div>

            <div className="bg-white rounded-xl shadow-sm overflow-hidden border border-gray-100">
                {loading ? (
                    <div className="p-8 text-center text-gray-500">Loading members...</div>
                ) : (
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-gray-50 border-b border-gray-100 text-gray-600 text-sm uppercase tracking-wider">
                                <th className="p-4 font-semibold">Name</th>
                                <th className="p-4 font-semibold">Email</th>
                                <th className="p-4 font-semibold">Phone</th>
                                <th className="p-4 font-semibold">Status</th>
                                <th className="p-4 font-semibold">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {members.length === 0 ? (
                                <tr><td colSpan="5" className="p-6 text-center text-gray-500">No members found.</td></tr>
                            ) : (
                                members.map(u => (
                                    <tr key={u._id} className="hover:bg-gray-50 transition-colors">
                                        <td className="p-4 font-medium text-gray-800">{u.fullName}</td>
                                        <td className="p-4 text-gray-600">{u.email}</td>
                                        <td className="p-4 text-gray-600">{u.phone || '-'}</td>
                                        <td className="p-4">
                                            <span className={`px-2 py-1 rounded-full text-xs font-medium ${u.status === 'active' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                                                {u.status}
                                            </span>
                                        </td>
                                        <td className="p-4">
                                            <button
                                                onClick={() => toggleStatus(u._id, u.status)}
                                                className={`px-3 py-1 rounded-lg text-sm font-medium transition-colors ${u.status === 'active'
                                                        ? 'bg-red-50 text-red-600 hover:bg-red-100'
                                                        : 'bg-green-50 text-green-600 hover:bg-green-100'
                                                    }`}
                                            >
                                                {u.status === 'active' ? 'Suspend' : 'Activate'}
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                )}
            </div>
        </div>
    );
};

export default Members;
